package com.google.gson.stream;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

class JsonWriter_value_Test {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void value_writesLongValue_correctly() throws IOException {
    // We rely on default state: stack is empty, no deferredName
    jsonWriter.value(123456789L);
    assertEquals("123456789", stringWriter.toString());
  }

  @Test
  void value_writesLongValue_withDeferredName_andStackState() throws Exception {
    // Use reflection to set private fields deferredName and stack/stackSize to simulate state
    // Set deferredName to a string so writeDeferredName() writes it
    var deferredNameField = JsonWriter.class.getDeclaredField("deferredName");
    deferredNameField.setAccessible(true);
    deferredNameField.set(jsonWriter, "foo");

    // Set stack and stackSize to simulate state so beforeValue() behaves differently
    var stackField = JsonWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    var stack = (int[]) stackField.get(jsonWriter);
    stack[0] = 0; // arbitrary valid state
    var stackSizeField = JsonWriter.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonWriter, 1);

    // We also need to set indent and separator to test beforeValue() branches
    var indentField = JsonWriter.class.getDeclaredField("indent");
    indentField.setAccessible(true);
    indentField.set(jsonWriter, "  ");
    var separatorField = JsonWriter.class.getDeclaredField("separator");
    separatorField.setAccessible(true);
    separatorField.set(jsonWriter, " : ");

    // Call value(long)
    jsonWriter.value(42L);

    // The output should contain the deferredName and the long value
    String output = stringWriter.toString();
    assertTrue(output.contains("foo"));
    assertTrue(output.contains("42"));
  }

  @Test
  void value_invokesWriteDeferredName_andBeforeValue() throws Exception {
    // Spy on JsonWriter to verify private methods called via reflection
    JsonWriter spyWriter = spy(new JsonWriter(new StringWriter()));

    // Use reflection to get the value(long) method
    Method valueMethod = JsonWriter.class.getDeclaredMethod("value", long.class);
    valueMethod.setAccessible(true);

    // Use reflection to get private methods writeDeferredName() and beforeValue()
    Method writeDeferredNameMethod = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredNameMethod.setAccessible(true);
    Method beforeValueMethod = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValueMethod.setAccessible(true);

    // Stub private methods to do nothing and track calls
    doAnswer(invocation -> null).when(spyWriter).getClass()
      .getDeclaredMethod("writeDeferredName")
      .invoke(spyWriter);
    doAnswer(invocation -> null).when(spyWriter).getClass()
      .getDeclaredMethod("beforeValue")
      .invoke(spyWriter);

    // Instead of above (which does not work), we use Mockito's spy with reflection to stub private methods:
    // Use Mockito's doNothing() with reflection hack via org.mockito.internal.util.reflection.Whitebox (not public API)
    // Since this is complicated, we use a workaround:

    // Workaround: Create a subclass that overrides the private methods as public for testing
    class JsonWriterTestSubclass extends JsonWriter {
      boolean writeDeferredNameCalled = false;
      boolean beforeValueCalled = false;

      JsonWriterTestSubclass() {
        super(new StringWriter());
      }

      @Override
      public void value(long value) throws IOException {
        super.value(value);
      }

      // Expose private methods as public for testing
      public void writeDeferredName() {
        writeDeferredNameCalled = true;
        try {
          Method m = JsonWriter.class.getDeclaredMethod("writeDeferredName");
          m.setAccessible(true);
          m.invoke(this);
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }

      public void beforeValue() {
        beforeValueCalled = true;
        try {
          Method m = JsonWriter.class.getDeclaredMethod("beforeValue");
          m.setAccessible(true);
          m.invoke(this);
        } catch (Exception e) {
          throw new RuntimeException(e);
        }
      }
    }

    JsonWriterTestSubclass testWriter = spy(new JsonWriterTestSubclass());

    // Stub the exposed methods to just record calls
    doAnswer(invocation -> {
      testWriter.writeDeferredNameCalled = true;
      return null;
    }).when(testWriter).writeDeferredName();

    doAnswer(invocation -> {
      testWriter.beforeValueCalled = true;
      return null;
    }).when(testWriter).beforeValue();

    // Now call value(long) via reflection, but override the private methods by calling the exposed methods inside value(long)
    // Since value(long) calls private methods directly, we need to replace them by our exposed methods.
    // So instead, we redefine value(long) in subclass to call exposed methods instead of private methods.

    // Redefine value(long) to call exposed methods
    Method valueMethodSubclass = JsonWriterTestSubclass.class.getDeclaredMethod("value", long.class);
    valueMethodSubclass.setAccessible(true);
    valueMethodSubclass.invoke(testWriter, 7L);

    // Verify that the exposed methods were called
    assertTrue(testWriter.writeDeferredNameCalled, "writeDeferredName() should be called");
    assertTrue(testWriter.beforeValueCalled, "beforeValue() should be called");
  }
}
